1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === Simplest cases ===
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // === Base premiums per item type ===
15	  it.todo("single plain sword → 105 G (100 base + 5 fee)");
16	  it.todo("single plain amulet → 65 G (60 base + 5 fee)");
17	  it.todo("single plain staff → 85 G (80 base + 5 fee)");
18	  it.todo("single plain potion → 45 G (40 base + 5 fee)");
19	
20	  // === Components and blocks ===
21	  it.todo("single rune → 30 G (25 base + 5 fee)");
22	  it.todo("2 runes → 55 G base premium (50 + 5 fee)");
23	  it.todo("3 runes → 65 G (block of 3 = 60 G base + 5 fee)");
24	  it.todo("4 runes → 105 G (no block; 4×25 = 100 + 5 fee)");
25	  it.todo("7 runes → 180 G (175 base + 5 fee)");
26	  it.todo("2 runes + 1 moonstone → 80 G (75 base + 5 fee, no block: different types)");
27	  it.todo("3 runes + 3 moonstones → 125 G (two separate blocks: 60+60 = 120 + 5 fee)");
28	
29	  // === Item-specific modifiers ===
30	  it.todo("cursed sword → 100 base + 50 curse + 5 fee = 155 G");
31	  it.todo("highly enchanted sword (enchantment 5) → 100 + 30 + 5 = 135 G");
32	  it.todo("sword with enchantment 4 → no high-enchantment surcharge, 105 G");
33	  it.todo("sword with enchantment 5 AND cursed → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
34	
35	  // === Customer-wide modifiers ===
36	  it.todo("customer with exactly 2 years → loyalty discount applies (sword: 100 - 20 + 10 first + 5 = 95 G)");
37	  it.todo("first insurance → 10% initial assessment surcharge (sword: 100 + 10 + 5 = 115 G for newcomer)");
38	  it.todo("follow-up contract → 15% discount on each contract after first");
39	
40	  // === Modifier scope on multi-item policies ===
41	  it.todo("cursed sword + plain amulet → 100+60 = 160 base; curse adds 50 (on sword only); 160+50+10(first)+5 = 225 G");
42	
43	  // === Rounding in MHPCO favor ===
44	  it.todo("premium calculation yielding 197.5 → 198 G (rounded up)");
45	  it.todo("payout calculation yielding 350.5 → 350 G (rounded down)");
46	
47	  // === Integration examples ===
48	  it.todo("newcomer with cursed sword (steel, ench 3), 0 years → 165 G");
49	  it.todo("long-standing customer's second contract: cursed sword ench 7, 3 years → 160 G");
50	  it.todo("first insurance surcharge applies per item even for follow-up contract");
51	
52	  // === Claim - basic ===
53	  it.todo("standard sword damage 500 → payout 400 (full minus 100 deductible)");
54	  it.todo("damage to rune (250 G value), damage 200 → payout 100");
55	  it.todo("high enchantment item (ench 8), damage 1000 → 50% then deductible = 400");
56	  it.todo("dragon material sword full reimbursement, damage 800, ench 5 → 700");
57	  it.todo("dragon material + high ench (ench 9), damage 1000 → 50% wins, then deductible = 400");
58	  it.todo("dragon-material sword ench exactly 8 damage 1000 → 400 (high-ench applies first)");
59	  it.todo("steel sword ench 9 damage 1000 → 50% then -100 = 400");
60	
61	  // === Deductible per damage event ===
62	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
63	
64	  // === Multiple items of same type ===
65	  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
66	  it.todo("two swords both damaged → each treated separately with own deductible");
67	  it.todo("damages contain more entries of a type than insured → claim rejected (CLI non-zero)");
68	
69	  // === Cap exhaustion ===
70	  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
71	  it.todo("cursed sword (premium modifiers don't affect cap) → cap based on unmodified insurance value 2000");
72	  it.todo("sword + 3 runes block → insurance sum 1750 (block doesn't affect insurance sum)");
73	  it.todo("sword cap 2000, two claims 1500 each → first 1400, second capped to 600");
74	  it.todo("remainingCap reaches 0 after exhausting cap");
75	
76	  // === Edge cases / errors ===
77	  it.todo("quote with unknown item type → CLI non-zero exit, error to stderr");
78	  it.todo("claim references item not in policy → CLI non-zero exit");
79	  it.todo("claim with negative damage amount → CLI non-zero exit");
80	
81	  // === CLI / scenario integration ===
82	  it.todo("full scenario with quote then claim returns results in order");
83	});
84

1	export const runScenario = (_scenario: unknown): unknown => {
2	  return { results: [{ premium: 5 }] };
3	};
